    <!-- Brand Zone Section -->
    <section id="brand-zone" class="py-16 bg-[#e1e1e1]">
      <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div class="bg-white rounded-3xl shadow-lg p-6 sm:p-10">
          <!-- Tabs -->
          <div class="flex items-center justify-center sm:justify-start space-x-6 sm:space-x-10 border-b border-gray-200 pb-4 mb-8 overflow-x-auto">
            <button 
              v-for="tab in brandTabs" 
              :key="tab"
              @click="activeBrandTab = tab"
              :class="[
                'text-lg font-semibold transition-colors duration-300 whitespace-nowrap',
                activeBrandTab === tab ? 'text-black' : 'text-gray-400 hover:text-gray-600'
              ]"
            >
              {{ tab }}
              <span 
                v-show="activeBrandTab === tab" 
                class="block h-0.5 w-1/2 mx-auto mt-1 bg-black rounded-full"
              ></span>
            </button>
          </div>

          <!-- Content Grid -->
                      <div class="grid grid-cols-1 lg:grid-cols-2 gap-8">
                          <!-- Large Item (Left) -->
            <div v-show="largeBrandItem" class="video-container relative rounded-2xl overflow-hidden group cursor-pointer aspect-w-16 aspect-h-9 lg:row-span-2">
              <!-- 占位符图片，在视频加载前显示 -->
              <img 
                v-if="!isVideoLoaded" 
                src="/imgs/test/Embroidery-workshop.webp" 
                alt="Factory Overview" 
                class="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                loading="lazy"
              />
              <!-- 视频元素 -->
              <video
                  v-if="isVideoVisible"
                  ref="videoRef"
                  :src="largeBrandItem?.image || '/imgs/test/Automated-Textile-Workshop.mp4'"
                  preload="metadata"
                  muted
                  loop
                  playsinline
                  class="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
                  :class="{ 'hidden': !isVideoLoaded }"
                  @loadeddata="onVideoLoaded"
                  @canplay="onVideoCanPlay"
                />

              <div class="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
              <div class="absolute inset-0 bg-gradient-to-t from-black/0 to-black/0 group-hover:from-black/50 group-hover:to-black/0 transition-all duration-300"></div>
              
              <div class="absolute bottom-0 left-0 p-6 text-white">
                <h3 class="text-2xl font-bold">{{ largeBrandItem?.title || 'Factory Overview' }}</h3>
                <p class="mt-1 text-lg">{{ largeBrandItem?.description || 'Professional manufacturing with modern equipment' }}</p>
              </div>
            </div>

            <!-- Small Items (Right) -->
            <div class="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div v-for="item in smallBrandItems" :key="item.id" class="flex flex-col">
                <div class="relative rounded-2xl overflow-hidden group cursor-pointer aspect-w-16 aspect-h-9">
                  <img :src="item?.image || '/imgs/test/Embroidery-workshop.webp'" :alt="item?.title || 'Workshop'" class="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105" />
                  <div class="absolute inset-0 bg-gradient-to-t from-black/0 to-black/0 group-hover:from-black/50 group-hover:to-black/0 transition-all duration-300"></div>
                </div>
                <p class="mt-3 text-center text-gray-700 font-medium">{{ item?.title || 'Workshop' }}</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- Contact Section -->
    <section class="py-16 bg-[#e1e1e1]" id="contact">
      <div class="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div class="flex flex-col md:flex-row rounded-2xl shadow-lg overflow-hidden">
          <!-- Left: Info -->
          <div class="bg-[#0a1445] flex-1 p-8 md:p-12 flex flex-col justify-center text-white">
            <div>
              <div class="text-yellow-400 font-semibold mb-2">
                {{ contactInfo?.custom || 'Contact us for more information on the latest offers!' }}
              </div>
              <h2 class="text-3xl sm:text-4xl font-extrabold mb-4 leading-tight">
                {{ contactInfo?.title || 'Have A Question? Our Expert' }}
              </h2>
              <div class="h-1 w-32 bg-yellow-400 mb-6"></div>
              <ul class="space-y-4 mb-8">
                <li v-for="(point, index) in contactInfo?.content || []" :key="index" class="flex items-center text-lg">
                  <span class="inline-block w-7 h-7 bg-yellow-400 rounded-full flex items-center justify-center text-[#0a1445] font-bold mr-3">✔</span>
                  {{ point }}
                </li>
              </ul>
              <div class="relative group">
                <img :src="contactInfo?.image || '/imgs/test/team-1-768x512.webp'" alt="Team" class="rounded-xl w-full max-w-xs mx-auto md:mx-0 shadow-lg" loading="lazy" decoding="async"/>
