    return {
      home: 'Home',
      products: 'Products',
      bags: 'Bags & Totes',
      homeDecor: 'Home Decor',
      accessories: 'Accessories',
      officeSupplies: 'Office Supplies',
      drinkware: 'Drinkware',
      handcrafts: 'Handicrafts'
    }[key] || key
  }
  
  // 解析当前路径
  const pathSegments = route.path.split('/').filter(segment => segment)
  const breadcrumbItems = []
  
  // 添加首页
  breadcrumbItems.push({
    '@type': 'ListItem',
    position: 1,
    name: getBreadcrumbText('home'),
    item: 'https://virtual-company.example'
  })
  
  // 根据路径生成面包屑
  if (pathSegments.length > 0) {
    let currentPath = 'https://virtual-company.example'
    
    pathSegments.forEach((segment, index) => {
      const position = index + 2
      currentPath += `/${segment}`
      
      // 根据路径段生成标题
      let name = segment
      if (segment === 'product') {
        name = getBreadcrumbText('products')
      } else if (segment === 'bags-totes') {
        name = getBreadcrumbText('bags')
      } else if (segment === 'home-decor') {
        name = getBreadcrumbText('homeDecor')
      } else if (segment === 'apparel-accessories') {
        name = getBreadcrumbText('accessories')
      } else if (segment === 'office-supplies') {
        name = getBreadcrumbText('officeSupplies')
      } else if (segment === 'drink-ware') {
        name = getBreadcrumbText('drinkware')
      } else if (segment === 'handi-crafts') {
        name = getBreadcrumbText('handcrafts')
      }
      
      breadcrumbItems.push({
        '@type': 'ListItem',
        position,
        name,
        item: currentPath
      })
    })
  }
  
  return {
    '@type': 'BreadcrumbList',
    itemListElement: breadcrumbItems
  }
}

